long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();
    if (n == 0 || k == 0) return 0;

    std::vector<long long> prefix_xor(n + 1, 0);
    for (int i = 1; i <= n; ++i) {
        prefix_xor[i] = prefix_xor[i-1] ^ nums[i-1];
    }

    std::vector<std::vector<long long>> dp(n + 1, std::vector<long long>(k + 1, 0));

    for (int i = 1; i <= n; ++i) {
        dp[i][1] = prefix_xor[i];
    }

    for (int j = 2; j <= k; ++j) {
        for (int i = j; i <= n; ++i) {
            long long min_max = LLONG_MAX;
            for (int m = j-1; m < i; ++m) {
                long long current_max = std::max(dp[m][j-1], prefix_xor[i] ^ prefix_xor[m]);
                if (current_max < min_max) {
                    min_max = current_max;
                }
            }
            dp[i][j] = min_max;
        }
    }

    return dp[n][k];
}

